{
    "level": "A2",
    "intro": "У цій темі ти навчишся відрізняти прикметники на <strong>-ed</strong> і <strong>-ing</strong>: <strong>-ed</strong> описує почуття людини, а <strong>-ing</strong> — річ, ситуацію або людину, що це почуття викликає.",
    "rules": [
        {
            "label": "FEELING",
            "color": "emerald",
            "text": "<strong>-ed</strong> = як хтось почувається:",
            "example": "I am bored."
        },
        {
            "label": "CAUSE",
            "color": "blue",
            "text": "<strong>-ing</strong> = що викликає почуття:",
            "example": "The film is boring."
        },
        {
            "label": "SAME ROOT",
            "color": "amber",
            "text": "Часто це одна й та сама пара: bored / boring, interested / interesting, tired / tiring.",
            "example": "She is interested in an interesting book."
        }
    ]
}

{
    "title": "1. Типові пари",
    "intro": "Найкраще вчити ці прикметники парами.",
    "items": [
        {
            "label": "почуття / причина",
            "title": "bored / boring",
            "subtitle": "I am bored. / The lesson is boring."
        },
        {
            "label": "почуття / причина",
            "title": "interested / interesting",
            "subtitle": "We are interested. / The topic is interesting."
        },
        {
            "label": "почуття / причина",
            "title": "excited / exciting",
            "subtitle": "They are excited. / The trip is exciting."
        },
        {
            "label": "почуття / причина",
            "title": "tired / tiring",
            "subtitle": "I am tired. / The journey is tiring."
        }
    ]
}

{
    "title": "2. Як це працює",
    "sections": [
        {
            "label": "Коли говоримо про людей",
            "color": "emerald",
            "description": "Якщо ти описуєш <strong>емоцію або стан людини</strong>, найчастіше потрібне <strong>-ed</strong>.",
            "examples": [
                {
                    "en": "I am really tired after work.",
                    "ua": "Я справді втомлений після роботи."
                },
                {
                    "en": "She felt embarrassed in class.",
                    "ua": "Вона почувалася збентеженою на уроці."
                },
                {
                    "en": "We were surprised by the news.",
                    "ua": "Ми були здивовані новиною."
                }
            ]
        },
        {
            "label": "Коли говоримо про річ або ситуацію",
            "color": "blue",
            "description": "Якщо щось <strong>викликає</strong> емоцію, зазвичай потрібне <strong>-ing</strong>.",
            "examples": [
                {
                    "en": "The lecture was boring.",
                    "ua": "Лекція була нудною."
                },
                {
                    "en": "It was an exciting match.",
                    "ua": "Це був захопливий матч."
                },
                {
                    "en": "The instructions are confusing.",
                    "ua": "Інструкції заплутані."
                }
            ]
        },
        {
            "label": "Порівняй значення в парі",
            "color": "amber",
            "description": "Одна літера змінює всю логіку речення.",
            "examples": [
                {
                    "en": "I am bored. / The film is boring.",
                    "ua": "Я нудьгую. / Фільм нудний."
                },
                {
                    "en": "They are excited. / The trip is exciting.",
                    "ua": "Вони схвильовані. / Поїздка захоплива."
                },
                {
                    "en": "He is confused. / The map is confusing.",
                    "ua": "Він розгублений. / Карта заплутана."
                }
            ],
            "note": "Спершу запитай себе: це почуття чи причина почуття?"
        }
    ]
}

{
    "title": "3. Типові помилки",
    "items": [
        {
            "label": "Помилка 1",
            "color": "rose",
            "title": "Boring про людину, яка нудьгує.",
            "wrong": "I am boring.",
            "right": "✅ <span class=\"font-mono\">I am bored.</span>"
        },
        {
            "label": "Помилка 2",
            "color": "amber",
            "title": "Bored про фільм або урок.",
            "wrong": "The lesson is bored.",
            "right": "✅ <span class=\"font-mono\">The lesson is boring.</span>"
        },
        {
            "label": "Помилка 3",
            "color": "sky",
            "title": "Плутанина в одній парі.",
            "wrong": "She is interesting in art.",
            "right": "✅ <span class=\"font-mono\">She is interested in art.</span>"
        }
    ]
}

{
    "title": "4. Короткий конспект",
    "items": [
        "<strong>-ed</strong> описує почуття або стан людини.",
        "<strong>-ing</strong> описує річ, подію чи людину, що викликає це почуття.",
        "Пари треба вчити разом: bored / boring, excited / exciting, interested / interesting.",
        "Якщо людина щось відчуває, найчастіше потрібне <strong>-ed</strong>.",
        "Якщо щось є причиною емоції, найчастіше потрібне <strong>-ing</strong>."
    ]
}

